import{_ as s,c as i,o as a,b as n}from"./chunks/framework.CDs6etjB.js";const t=JSON.parse('{"title":"Context trong Perl","description":"Cách scalar, list và void context ảnh hưởng tới biểu thức trong Perl.","frontmatter":{"footer":true,"title":"Context trong Perl","description":"Cách scalar, list và void context ảnh hưởng tới biểu thức trong Perl.","authors":["lethanh"],"date":"2026-05-09T00:00:00.000Z","outline":"deep","image":"https://static-cdn.thanhlv.com/study/thanhlv-study-2026/perl.jpg","draft":false,"group":"1. Perl"},"headers":[{"level":2,"title":"1. Scalar context","slug":"_1-scalar-context","link":"#_1-scalar-context","children":[]},{"level":2,"title":"2. List context","slug":"_2-list-context","link":"#_2-list-context","children":[]},{"level":2,"title":"3. Void context","slug":"_3-void-context","link":"#_3-void-context","children":[]},{"level":2,"title":"wantarray để nhận biết context","slug":"wantarray-đe-nhan-biet-context","link":"#wantarray-đe-nhan-biet-context","children":[]},{"level":2,"title":"Kết luận","slug":"ket-luan","link":"#ket-luan","children":[]}],"relativePath":"study/thanhlv-study-2026/2026-05-09-context-trong-perl.md","filePath":"study/thanhlv-study-2026/2026-05-09-context-trong-perl.md","lastUpdated":1778130283000}');const e=s({name:"study/thanhlv-study-2026/2026-05-09-context-trong-perl.md"},[["render",function(s,t,e,l,h,p){return a(),i("div",null,[...t[0]||(t[0]=[n('<nav class="table-of-contents"><ul><li><a href="#_1-scalar-context">1. Scalar context</a></li><li><a href="#_2-list-context">2. List context</a></li><li><a href="#_3-void-context">3. Void context</a></li><li><a href="#wantarray-đe-nhan-biet-context">wantarray để nhận biết context</a></li><li><a href="#ket-luan">Kết luận</a></li></ul></nav><h1 id="context-trong-perl" tabindex="-1">Context trong Perl <a class="header-anchor" href="#context-trong-perl" aria-label="Permalink to &quot;Context trong Perl&quot;">​</a></h1><p><code>Context</code> là một khái niệm cốt lõi trong Perl: cùng một biểu thức có thể cho kết quả khác nhau tùy vào ngữ cảnh nơi nó được dùng.</p><p>Ba loại context phổ biến là:</p><ul><li><code>scalar context</code></li><li><code>list context</code></li><li><code>void context</code></li></ul><h2 id="_1-scalar-context" tabindex="-1">1. Scalar context <a class="header-anchor" href="#_1-scalar-context" aria-label="Permalink to &quot;1. Scalar context&quot;">​</a></h2><p>Trong <code>scalar context</code>, biểu thức được kỳ vọng trả về một giá trị đơn.</p><div class="language-perl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">perl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @array = (1, 2, 3);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $count = @array;     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># @array ở scalar context -&gt; số phần tử</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$count</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Một ví dụ khác rất hay gây nhầm:</p><div class="language-perl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">perl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $x = (10, 20, 30);   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Toán tử comma trong scalar context -&gt; phần tử cuối</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 30</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Lưu ý: không phải &quot;nhiều giá trị thì lấy phần tử đầu tiên&quot;; trong ví dụ comma operator ở scalar context, Perl lấy <strong>giá trị cuối</strong>.</p><h2 id="_2-list-context" tabindex="-1">2. List context <a class="header-anchor" href="#_2-list-context" aria-label="Permalink to &quot;2. List context&quot;">​</a></h2><p>Trong <code>list context</code>, biểu thức được kỳ vọng trả về danh sách giá trị.</p><div class="language-perl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">perl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @array = (1, 2, 3);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @copy = @array;      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># @array ở list context -&gt; toàn bộ phần tử</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> join</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;, &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, @copy), </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1, 2, 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>List context thường xuất hiện khi gán cho mảng, truyền danh sách đối số, hoặc khi dùng các hàm kỳ vọng danh sách.</p><h2 id="_3-void-context" tabindex="-1">3. Void context <a class="header-anchor" href="#_3-void-context" aria-label="Permalink to &quot;3. Void context&quot;">​</a></h2><p><code>Void context</code> là khi kết quả biểu thức bị bỏ qua.</p><div class="language-perl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">perl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sub</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> compute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 99;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compute();  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># gọi hàm nhưng bỏ qua giá trị trả về -&gt; void context</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>Void context</code> hữu ích khi bạn chỉ cần side effect (ví dụ: ghi log, cập nhật state), không cần dùng kết quả trả về.</p><h2 id="wantarray-đe-nhan-biet-context" tabindex="-1"><code>wantarray</code> để nhận biết context <a class="header-anchor" href="#wantarray-đe-nhan-biet-context" aria-label="Permalink to &quot;`wantarray` để nhận biết context&quot;">​</a></h2><p><code>wantarray</code> giúp hàm biết nó đang được gọi trong context nào:</p><ul><li><code>undef</code>: void context</li><li><code>true</code>: list context</li><li><code>false</code> (defined nhưng falsy): scalar context</li></ul><div class="language-perl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">perl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sub</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> example</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (!</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">defined</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> wantarray</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        print</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Void context</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">wantarray</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (1, 2, 3);   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># list context</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 42;              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># scalar context</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @list = example();       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (1, 2, 3)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $scalar = example();     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 42</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">example();                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># in &quot;Void context&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h2 id="ket-luan" tabindex="-1">Kết luận <a class="header-anchor" href="#ket-luan" aria-label="Permalink to &quot;Kết luận&quot;">​</a></h2><p>Hiểu đúng context giúp bạn:</p><ul><li>dự đoán chính xác giá trị trả về</li><li>tránh bug do dùng sai kiểu ngữ cảnh</li><li>viết hàm linh hoạt hơn với <code>wantarray</code></li></ul><p>Khi đọc hoặc viết Perl, luôn tự hỏi: &quot;Biểu thức này đang ở scalar, list hay void context?&quot;.</p>',27)])])}]]);export{t as __pageData,e as default};
